UPDATE hpeapm."spl_model_type" SET write_time=CURRENT_TIMESTAMP
,audit_model_type = #{auditModelType}
,dock_deputy = #{dockDeputy}
,dock_people = #{dockPeople}
,dock_dept = #{deckDept}
,def_exam_user = #{defExamUser}
,def_exam_userDept LIKE '%'||#{defExamUserDept}||'%'
,def2_exam_user LIKE '%'||#{def2ExamUser}||'%'
,def2_exam_userdepy LIKE '%'||#{def2ExamUserDepy}||'%'
,share_user LIKE '%'||#{shareUser}||'%'
,share_user_depy LIKE '%'||#{shareUserDepy}||'%'
,model_owner LIKE '%'||#{modelOwner}||'%'
,model_owner_depy LIKE '%'||#{modelOwnerDepy}||'%'
WHERE audit_model_number LIKE '%'||#{auditModelNumber}||'%'

