,audit_model_number = #{audit_model_number}
,submit_user LIKE '%'||#{submit_user}||'%' ,sub_depy LIKE '%'||#{sub_depy}||'%' ,submit_time LIKE '%'||#{submit_time}||'%' ,submit_remarks LIKE '%'||#{submit_remarks}||'%' ,examine_type LIKE '%'||#{examine_type}||'%' ,submit_user LIKE '%'||#{submit_user}||'%' ,submit_time LIKE '%'||#{submit_time}||'%' ,submit_remarks LIKE '%'||#{submit_remarks}||'%' ,exam_depy=#{exam_depy} ,examine_user LIKE '%'||#{examine_user}||'%' ,process_instId LIKE '%'||#{process_instId}||'%' ,workItem_Id LIKE '%'||#{workItem_Id}||'%' ,examine_dept LIKE '%'||#{examine_dept}||'%' ,examine_time LIKE '%'||#{examine_time}||'%' ,examine_result LIKE '%'||#{examine_result}||'%' ,examine_message_id = #{examine_message_id}
,is_complete LIKE '%'||#{is_complete}||'%' ,now_category LIKE '%'||#{now_category}||'%' ,examine_category LIKE '%'||#{examine_category}||'%'
